{
    if (c == std::cout.widen('.') && pbase() && this->pptr() && *(pptr()-1) == std::wstring(this->pbase(), pptr()))
        std::cout << std::endl;
    else
        std::cout.put(std::wcout.widen(c));
    return 0;
}
